import { memo, useState } from "react";

// Archived-conversation transcript. Support exports routinely hold ~5,000
// messages, and the filter box re-renders this component on every keystroke.

type ChatMessage = {
  id: string;
  author: string;
  body: string;
  sentAt: string;
};

type RowProps = {
  message: ChatMessage;
  selected: boolean;
  onSelect: (id: string) => void;
};

const MessageRow = memo(function MessageRow({ message, selected, onSelect }: RowProps) {
  return (
    <li
      className={selected ? "row row-selected" : "row"}
      onClick={() => onSelect(message.id)}
    >
      <span className="author">{message.author}</span>
      <span className="body">{message.body}</span>
      <time className="stamp">{message.sentAt}</time>
    </li>
  );
});

export function MessageList({ messages }: { messages: ChatMessage[] }) {
  const [query, setQuery] = useState("");
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const visible = query
    ? messages.filter((m) => m.body.toLowerCase().includes(query.toLowerCase()))
    : messages;

  return (
    <div className="transcript">
      <input
        className="filter"
        placeholder="Filter messages"
        value={query}
        onChange={(e) => setQuery(e.target.value)}
      />
      <ul className="rows">
        {visible.map((m) => (
          <MessageRow key={m.id} message={m} selected={m.id === selectedId} onSelect={setSelectedId} />
        ))}
      </ul>
    </div>
  );
}

