const MessageRow = memo(function MessageRow({ message, selected, highlight, onSelect }: RowProps) {
  return (
    <li
      className={(selected ? "row row-selected" : "row") + " accent-" + highlight.accent}
      onClick={() => onSelect(message.id)}
    >
      <span className="author">{message.author}</span>
      <span className="body">{message.body}</span>
      {highlight.term ? <em className="hit">{highlight.term}</em> : null}
      <time className="stamp">{message.sentAt}</time>
    </li>
  );
});

export function MessageList({ messages, accent }: { messages: ChatMessage[]; accent: string }) {
  const [query, setQuery] = useState("");
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const visible = query
    ? messages.filter((m) => m.body.toLowerCase().includes(query.toLowerCase()))
    : messages;

  return (
    <div className="transcript">
      <input
        className="filter"
        placeholder="Filter messages"
        value={query}
        onChange={(e) => setQuery(e.target.value)}
      />
      {visible.length === 0 ? <EmptyNotice /> : null}
      <ul className="rows">
        {visible.map((m) => (
          <MessageRow
            key={m.id}
            message={m}
            selected={m.id === selectedId}
            highlight={{ term: query, accent }}
            onSelect={(id) => {
              setSelectedId(id);
              document.getElementById("ctx-" + id)?.scrollIntoView();
            }}
          />
        ))}
      </ul>
    </div>
  );
