import { useEffect, useState } from "react";

type AuditEvent = {
  id: string;
  actor: string;
  action: string;
  at: string;
};

// Read-only audit trail for the workspace admin page.

function describe(event: AuditEvent): string {
  return event.actor + " " + event.action;
}

export function AuditFeed({ initialEvents }: { initialEvents: AuditEvent[] }) {
  const [events, setEvents] = useState(initialEvents);

  // Live mode: the trail keeps every event for the session — after an hour of
  // normal workspace activity that is ~10,000 entries, arriving about one per
  // second. Each arrival is prepended so the newest entry sits on top.
  useEffect(() => {
    const stream = new EventSource("/internal/audit/stream");
    stream.onmessage = (msg) => {
      const entry = JSON.parse(msg.data) as AuditEvent;
      setEvents((prev) => [entry, ...prev]);
    };
    return () => stream.close();
  }, []);

  return (
    <section className="audit-feed">
      <h2 className="heading">Audit trail</h2>
      <ol className="entries">
        {events.map((event, i) => (
          <li key={i} className="entry" title={describe(event)}>
            <span className="actor">{event.actor}</span>
            <span className="action">{event.action}</span>
            <time className="at">{event.at}</time>
          </li>
        ))}
      </ol>
    </section>
  );
}

