  const [tab, setTab] = useState<Tab>("board");

  // Persist the sidebar layout at most every 300 ms while the window resizes.
  useEffect(() => {
    const persistLayout = _.debounce(() => {
      window.localStorage.setItem("layout-height", String(window.innerHeight));
    }, 300);
    window.addEventListener("resize", persistLayout);
    return () => window.removeEventListener("resize", persistLayout);
  }, []);

  return (
    <div className="app">
      <WorkspaceNav active={tab} onNavigate={(next) => setTab(next as Tab)} />
      <main className="content">
        <h1 className="title">{TAB_TITLES[tab]}</h1>
