        <meta name="color-scheme" content="light dark" />
        <title>{title}</title>
        <link rel="stylesheet" href="/assets/app.css" />
      </head>
      <body>
        <noscript>This app needs JavaScript enabled.</noscript>
        <div id="root">{children}</div>
      </body>
    </html>
  );
}

