export type Sku = { id: string; label: string; unitPrice: number };

// Fuzzy ranking for the picker. Edit distance is O(len(a) * len(b)) per
// candidate, and ranking scores the WHOLE catalog before sorting.
export function rankSkus(catalog: Sku[], term: string): Sku[] {
  if (term.trim() === "") return catalog.slice(0, 50);
  const needle = term.toLowerCase();
  return catalog
    .map((sku) => ({ sku, score: editDistance(sku.label.toLowerCase(), needle) }))
    .sort((a, b) => a.score - b.score)
    .slice(0, 50)
    .map((ranked) => ranked.sku);
}

function editDistance(a: string, b: string): number {
  const rows = a.length + 1;
  const cols = b.length + 1;
  const d: number[][] = Array.from({ length: rows }, () => new Array(cols).fill(0));
  for (let i = 0; i < rows; i += 1) d[i][0] = i;
  for (let j = 0; j < cols; j += 1) d[0][j] = j;
  for (let i = 1; i < rows; i += 1) {
    for (let j = 1; j < cols; j += 1) {
      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
      d[i][j] = Math.min(d[i - 1][j] + 1, d[i][j - 1] + 1, d[i - 1][j - 1] + cost);
    }
  }
  return d[rows - 1][cols - 1];
}

