  return (
    <tr className="integration">
      <td className="name">{integration.name}</td>
      <td className="kind">{integration.kind}</td>
      <td className="state">{integration.enabled ? "On" : "Off"}</td>
    </tr>
  );
});

export function IntegrationsTable({ initial }: { initial: Integration[] }) {
  const sorted = useMemo(() => [...initial].sort((a, b) => a.name.localeCompare(b.name)), [initial]);

  return (
    <table className="integrations">
      <tbody>
        {sorted.map((integration) => (
          <IntegrationRow key={integration.id} integration={integration} />
        ))}
      </tbody>
    </table>
  );
}

