  const sorted = useMemo(() => [...items].sort((a, b) => a.name.localeCompare(b.name)), [items]);

  return (
    <table className="integrations">
      <tbody>
        {sorted.map((integration) => (
          <IntegrationRow key={integration.id} integration={integration} onToggle={handleToggle} />
        ))}
      </tbody>
