import { useEffect, useState } from "react";

type CustomerHit = { id: string; name: string; company: string };

// Sidebar picker used by the billing screen to attach a customer to an invoice.
// Directory search spans ~50,000 customer records: the SERVER does the matching
// and returns a 20-row page; the client only debounces, aborts, and renders.

export function CustomerLookup({ recent, onChoose }: { recent: CustomerHit[]; onChoose: (id: string) => void }) {
  const [chosen, setChosen] = useState<string | null>(null);
  const [term, setTerm] = useState("");
  const [hits, setHits] = useState<CustomerHit[]>([]);

  useEffect(() => {
    if (term.trim().length < 2) {
      setHits([]);
      return;
    }
    const ctrl = new AbortController();
    const timer = window.setTimeout(() => {
      fetch("/api/customers/search?q=" + encodeURIComponent(term), { signal: ctrl.signal })
        .then((res) => res.json())
        .then((data: { hits: CustomerHit[] }) => setHits(data.hits))
        .catch((err: unknown) => {
          if ((err as Error).name !== "AbortError") setHits([]);
        });
    }, 250);
    return () => {
      ctrl.abort();
      window.clearTimeout(timer);
    };
  }, [term]);

  const shown = term.trim().length >= 2 ? hits : recent;

  return (
    <div className="customer-lookup">
      <input
        className="search"
        placeholder="Search all customers"
        value={term}
        onChange={(e) => setTerm(e.target.value)}
      />
      <h4 className="heading">{term.trim().length >= 2 ? "Matches" : "Recent customers"}</h4>
      <ul className="hits">
        {shown.map((hit) => (
          <li key={hit.id} className={hit.id === chosen ? "hit hit-chosen" : "hit"}>
            <button
              className="choose"
              onClick={() => {
                setChosen(hit.id);
                onChoose(hit.id);
              }}
            >
