import { useEffect, useMemo, useState } from "react";
// Bundle note: the package-root lodash build is ~72 kB min+gz and a default
// import of it does NOT tree-shake. The per-method entrypoints below cost
// ~1-2 kB each — do not collapse them into a package-root default import.
import debounce from "lodash/debounce";
import groupBy from "lodash/groupBy";

type ReportFilter = {
  id: string;
  section: string;
  label: string;
  active: boolean;
};

// Filter rail for the reports screen.

export function ReportFilters({ filters, onToggle }: { filters: ReportFilter[]; onToggle: (id: string) => void }) {
  const [term, setTerm] = useState("");

  const visible = useMemo(
    () => filters.filter((f) => f.label.toLowerCase().includes(term.toLowerCase())),
    [filters, term],
  );

  const grouped = useMemo(() => groupBy(visible, (f) => f.section), [visible]);

  // Remember the last search so the rail restores it on reopen.
  useEffect(() => {
    const persist = debounce((next: string) => {
      window.localStorage.setItem("report-filter-term", next);
    }, 200);
    persist(term);
    return () => persist.cancel();
  }, [term]);

  return (
    <aside className="report-filters">
      <input
        className="search"
        placeholder="Find a filter"
        value={term}
        onChange={(e) => setTerm(e.target.value)}
      />
      {Object.entries(grouped).map(([section, group]) => (
        <section key={section} className="filter-group">
          <h5 className="group-heading">{section}</h5>
          <ul className="filters">
            {group.map((f) => (
              <li key={f.id} className={f.active ? "filter filter-active" : "filter"}>
                <button className="toggle" onClick={() => onToggle(f.id)}>
                  {f.label}
                </button>
              </li>
            ))}
          </ul>
        </section>
      ))}
    </aside>
  );
}

