import { useEffect, useState } from "react";

type ActivityEntry = {
  id: string;
  summary: string;
  actor: string;
  at: string;
};

// Sidebar panel; the parent keeps it mounted across tab switches.

export function ProjectActivity({ projectId }: { projectId: string }) {
  const [expanded, setExpanded] = useState(false);
  const [entries, setEntries] = useState<ActivityEntry[]>([]);

  // One request per project; aborted when the panel unmounts or the project
  // changes. AbortError is the expected rejection on cleanup.
  useEffect(() => {
    const ctrl = new AbortController();
    fetch("/api/projects/" + projectId + "/activity", { signal: ctrl.signal })
      .then((res) => res.json())
      .then((data: { entries: ActivityEntry[] }) => setEntries(data.entries))
      .catch((err: unknown) => {
        if ((err as Error).name !== "AbortError") setEntries([]);
      });
    return () => ctrl.abort();
  }, [projectId]);

  const shown = expanded ? entries : entries.slice(0, 5);

  return (
    <aside className="activity">
      <h3 className="heading">Recent activity</h3>
      <ul className="entries">
        {shown.map((entry) => (
          <li key={entry.id} className="entry">
            <span className="summary">{entry.summary}</span>
            <span className="meta">
              {entry.actor} - {entry.at}
            </span>
          </li>
        ))}
      </ul>
      <button className="toggle" onClick={() => setExpanded((v) => !v)}>
        {expanded ? "Show fewer" : "Show all"}
      </button>
    </aside>
  );
}

