import { useRef } from 'react';

export interface TimelineItem {
  id: string;
  label: string;
}

export function Timeline({ items }: { items: TimelineItem[] }) {
  const listRef = useRef<HTMLUListElement>(null);
  const handleScroll = () => {
    const rows = listRef.current?.querySelectorAll<HTMLElement>('.timeline-row') ?? [];
    for (const row of rows) {
      const rect = row.getBoundingClientRect();
      row.style.height = `${Math.max(32, rect.height)}px`;
      row.style.opacity = rect.top < 0 ? '0.5' : '1';
    }
  };
  return (
    <ul ref={listRef} className="timeline" onScroll={handleScroll}>
      {items.map((item) => (
        <li key={item.id} className="timeline-row">
          {item.label}
        </li>
      ))}
    </ul>
  );
}
